import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    width = int(input_data[0])
    height = int(input_data[1])
    max_loops = int(input_data[2])

    grid_str = input_data[3:]
    size = width * height

    walls = [False] * size
    door_mask = [0] * size
    switch_mask = [0] * size
    S_pos = E_pos = -1

    for y in range(height):
        for x in range(width):
            pos = y * width + x
            c = grid_str[y][x]
            if c == '#': walls[pos] = True
            elif c == 'S': S_pos = pos
            elif c == 'E': E_pos = pos
            elif 'a' <= c <= 'z': switch_mask[pos] = 1 << (ord(c) - ord('a'))
            elif 'A' <= c <= 'Z': door_mask[pos] = 1 << (ord(c) - ord('A'))

    moves = [('W', 0), ('U', -width), ('R', 1), ('L', -1), ('D', width)]

    # Graphe d'adjacence basique sans contrainte de portes
    adj_all = [[] for _ in range(size)]
    for pos in range(size):
        if walls[pos]: continue
        for m_char, delta in moves:
            npos = pos + delta
            if not walls[npos]:
                adj_all[pos].append((npos, m_char))

    def get_dist(targets, valid_adj):
        """BFS multi-cibles classique sur un graphe pré-filtré"""
        dist = [9999] * size
        q = targets[:]
        for t in q:
            dist[t] = 0
        head = 0
        while head < len(q):
            pos = q[head]
            head += 1
            d = dist[pos] + 1
            for npos, m_char in valid_adj[pos]:
                if m_char == 'W': continue # Pas de surplace pendant le calcul de distance
                if dist[npos] == 9999:
                    dist[npos] = d
                    q.append(npos)
        return dist

    def get_positions(path_str):
        pos = S_pos
        res = [pos]
        for c in path_str:
            if c == 'W': pos += 0
            elif c == 'U': pos -= width
            elif c == 'D': pos += width
            elif c == 'L': pos -= 1
            elif c == 'R': pos += 1
            res.append(pos)
        return res

    def solve_for_N_T(N, T):
        def backtrack(loop_idx, open_doors, ghost_paths):
            # 1. PRÉ-FILTRAGE DU GRAPHE POUR LA BOUCLE (Portes statiques)
            valid_adj = [[] for _ in range(size)]
            for pos in range(size):
                if walls[pos]: continue
                for npos, m_char in adj_all[pos]:
                    req = door_mask[npos]
                    if not req or (open_doors & req):
                        valid_adj[pos].append((npos, m_char))

            # 2. IDENTIFICATION DES CIBLES RESTANTES
            eff_sw = [0] * size
            targets = []
            for i in range(size):
                if switch_mask[i] and not (open_doors & switch_mask[i]):
                    eff_sw[i] = switch_mask[i]
                    targets.append(i)

            dist_to_E = get_dist([E_pos], valid_adj)
            dist_to_targets = get_dist(targets, valid_adj) if targets else []

            # 3. ÉLAGAGE PRÉMATURÉ (Heuristique forte)
            if loop_idx == N - 1:
                if dist_to_E[S_pos] > T: return None
            else:
                if not targets or dist_to_targets[S_pos] > T: return None

            # 4. GESTION DES FANTÔMES O(1)
            ghost_occ = [[False] * size for _ in range(T + 1)]
            for g in ghost_paths:
                for t in range(T + 1):
                    ghost_occ[t][g[t]] = True

            # 5. RECHERCHE DP DYNAMIQUE (Ultra serrée)
            active = {(S_pos, 0): {""}}
            K_limit = 3 if loop_idx < N - 1 else 1

            for t in range(T):
                next_active = {}
                g_t1 = ghost_occ[t+1]
                rem_time = T - t - 1

                for (pos, sw), prefixes in active.items():
                    for npos, m_char in valid_adj[pos]:
                        # Collisions interdites en dehors du point S
                        if npos != S_pos and g_t1[npos]: continue

                        if loop_idx == N - 1:
                            if dist_to_E[npos] > rem_time: continue
                            nsw = 0
                        else:
                            if sw == 0 and dist_to_targets[npos] > rem_time: continue
                            nsw = sw | eff_sw[npos]

                        state = (npos, nsw)
                        if state not in next_active:
                            next_active[state] = set()

                        for p in prefixes:
                            next_active[state].add(p + m_char)

                # Nettoyage et conservation des K-meilleurs chemins lexicographiques
                active = {}
                for state, p_set in next_active.items():
                    lst = list(p_set)
                    lst.sort(reverse=True)
                    active[state] = set(lst[:K_limit])

                if not active: return None

            # 6. RETOUR DES RÉSULTATS
            if loop_idx == N - 1:
                final_paths = active.get((E_pos, 0))
                if final_paths:
                    lst = list(final_paths)
                    lst.sort(reverse=True)
                    return [lst[0]]
                return None
            else:
                candidates = []
                for (pos, sw), prefixes in active.items():
                    if sw > 0:
                        for p in prefixes:
                            candidates.append((p, sw))

                if not candidates: return None

                # Regroupement par interrupteurs trouvés
                grouped = {}
                for p, sw in candidates:
                    if sw not in grouped: grouped[sw] = []
                    grouped[sw].append(p)

                final_cands = []
                for sw, lst in grouped.items():
                    lst.sort(reverse=True)
                    for p in lst[:2]:  # Garder les 2 meilleurs par combinaison
                        final_cands.append((p, sw))

                final_cands.sort(reverse=True, key=lambda x: x[0])

                # Backtracking dans les univers temporels suivants
                for path, sw in final_cands:
                    new_ghost = get_positions(path)
                    res = backtrack(loop_idx + 1, open_doors | sw, ghost_paths + [new_ghost])
                    if res is not None:
                        return [path] + res

                return None

        return backtrack(0, 0, [])

    # Calcul de la borne minimale absolue (T_start) pour Iterative Deepening
    adj_all_open = [[] for _ in range(size)]
    for pos in range(size):
        if walls[pos]: continue
        for npos, m_char in adj_all[pos]:
            adj_all_open[pos].append((npos, m_char))

    min_dist = get_dist([E_pos], adj_all_open)[S_pos]
    if min_dist == 9999: return

    for T in range(min_dist, 500):
        for N in range(1, max_loops + 1):
            plan = solve_for_N_T(N, T)
            if plan:
                for path in plan:
                    print(" ".join(list(path)))
                return

if __name__ == '__main__':
    solve()

data.constraints:
- {{3}} ≤ [[width]] ≤ {{30}}
- {{3}} ≤ [[height]] ≤ {{20}}
- {{1}} ≤ [[max_loops]] ≤ {{5}}
- Every side of the grid is a wall ({{#}}).
- The grid contains exactly one {{S}} and one {{E}}.
- Each switch letter ({{a-z}}) and each door letter ({{A-Z}}) appears exactly once, forming a one-to-one correspondence.
- Every door is placed so that it blocks all possible routes through its location unless it is opened; it cannot be bypassed by walking around it.
- Every test case is guaranteed to have a solution.
